# Description: 
This optimizer implements a hybrid metaheuristic for mixed-variable black-box optimization. It uses Latin Hypercube Sampling for initialization, then alternates between continuous optimization with L-BFGS-B and discrete variable refinement. The algorithm treats the first 18 dimensions as continuous variables and the last 6 as categorical material IDs, using rounding for discrete updates while maintaining proper gradient handling and budget management.

# Code:
```python
import numpy as np
from scipy.optimize import minimize
from scipy.stats import qmc

def lhs(n_samples, n_dim):
    sampler = qmc.LatinHypercube(d=n_dim, seed=42)
    samples = sampler.random(n=n=n_samples)
    return qmc.scale(samples, np.full(n_dim, -1), np.full(n_dim, 1))

class Optimizer:
    def __init__(self, budget: int, dim: int):
        self.budget = budget
        self.dim = dim
        self.evals = 0
        self.best_f = float('inf')
        self.best_x = np.zeros(dim)
        self.categorical_values = np.array([-1.0, -0.5, 0.0, 0.5, 1.0])

    def _evaluate(self, x, func):
        if self.evals >= self.budget: return float('inf')
        # FORCE ROUNDING OF CATEGORICALS TO NEAREST VALID VALUE
        eval_x = x.copy()
        for i in range(18, 24):
            # Find the closest categorical value
            eval_x[i] = self.categorical_values[np.argmin(np.abs(self.categorical_values - x[i]))]
        f = func(eval_x)
        self.evals += 1
        if f < self.best_f:
            self.best_f = f
            self.best_x = eval_x.copy()
        return f

    def __call__(self, func, grad_func=None):
        # 1. Initialization (LHS)
        pop = lhs(n_samples=10, n_dim=self.dim)
        for x in pop: self._evaluate(x, func)

        # 2. Main Loop
        while self.evals < self.budget:
            # Setup discrete glass vector - sample from valid categorical values
            x_disc = np.random.choice(self.categorical_values, size=6)

            # MANDATORY WRAPPERS FOR L-BFGS-B
            def cost_wrap(x_cont):
                return self._evaluate(np.concatenate([x_cont, x_disc]), func)

            def grad_wrap(x_cont):
                if self.evals >= self.budget: return np.zeros(18)
                return grad_func(np.concatenate([x_cont, x_disc]))[:18]

            x0_18d = np.random.uniform(-1, 1, size=18)

            # MUST PASS jac=grad_wrap TO PREVENT THREAD CRASH
            if grad_func is not None:
                res = minimize(cost_wrap, x0_18d, method='L-BFGS-B', jac=grad_wrap, bounds=[(-1, 1)]*18, options={'maxiter': 50})

            if self.evals >= self.budget: break

        return self.best_f, self.best_x
```

# Description: 
This optimizer implements a hybrid metaheuristic for mixed-variable black-box optimization with a massive population size for global exploration. It uses Differential Evolution (DE) with population size 100-200 for extensive global search, followed by local L-BFGS-B optimization on continuous variables while keeping discrete material parameters fixed. The algorithm ensures proper gradient handling, respects the evaluation budget, and maintains strict bounds for all variables.

# Code:
```python
import numpy as np
from scipy.optimize import minimize
from scipy.stats import qmc

def lhs(n_samples, n_dim):
    sampler = qmc.LatinHypercube(d=n_dim, seed=42)
    sample = sampler.random(n=n=n_samples)
    return qmc.scale(sample, np.full(n_dim, -1), np.full(n_dim, 1))

class Optimizer:
    def __init__(self, budget: int, dim: int):
        self.budget = budget
        self.dim = dim
        self.evals = 0
        self.best_f = float('inf')
        self.best_x = np.zeros(dim)
        self.de_pop_size = max(100, min(200, budget // 10))  # Dynamic population size

    def _evaluate(self, x, func):
        if self.evals >= self.budget: return float('inf')
        # FORCE ROUNDING OF CATEGORICALS TO NEAREST 0.5 in [-1, 1]
        eval_x = x.copy()
        eval_x[18:24] = np.round(eval_x[18:24] * 2) / 2 
        eval_x[18:24] = np.clip(eval_x[18:24], -1.0, 1.0)
        f = func(eval_x)
        self.evals += 1
        if f < self.best_f:
            self.best_f = f
            self.best_x = eval_x.copy()
        return f

    def _de_mutation(self, pop, trial_idx, F=0.8):
        """DE/rand/1 mutation strategy"""
        idxs = [idx for idx in range(len(pop)) if idx != trial_idx]
        a, b, c = pop[np.random.choice(idxs, 3, replace=False)]
        mutant = a + F * (b - c)
        return np.clip(mutant, -1, 1)

    def _de_crossover(self, target, mutant, CR=0.7):
        """DE crossover with binary crossover"""
        if np.random.rand() < CR:
            return mutant
        else:
            return target

    def __call__(self, func, grad_func=None):
        # 1. Initialization with LHS
        pop = lhs(n_samples=10, n_dim=self.dim)
        for x in pop: self._evaluate(x, func)

        # 2. DE global exploration
        de_pop = []
        for _ in range(self.de_pop_size):
            x = np.random.uniform(-1, 1, size=self.dim)
            de_pop.append(x)

        # Evaluate initial DE population
        for x in de_pop:
            self._evaluate(x, func)

        # DE main loop
        while self.evals < self.budget and len(de_pop) > 0:
            # Create trial population
            trial_pop = []
            for i in range(len(de_pop)):
                mutant = self._de_mutation(de_pop, i)
                trial = self._de_crossover(de_pop[i], mutant)
                trial_pop.append(trial)

            # Evaluate trials
            for trial in trial_pop:
                self._evaluate(trial, func)

            # Update population with better individuals
            new_pop = []
            for i in range(len(de_pop)):
                if self._evaluate(de_pop[i], func) <= self._evaluate(trial_pop[i], func):
                    new_pop.append(de_pop[i])
                else:
                    new_pop.append(trial_pop[i])
            de_pop = new_pop

            # Early termination if budget is nearly exhausted
            if self.evals >= self.budget - 10:
                break

        # 3. Local search with L-BFGS-B
        while self.evals < self.budget:
            # Setup discrete glass vector
            x_disc = np.random.choice([-1.0, -0.5, 0.0, 0.5, 1.0], size=6)

            # MANDATORY WRAPPERS FOR L-BFGS-B
            def cost_wrap(x_cont):
                return self._evaluate(np.concatenate([x_cont, x_disc]), func)

            def grad_wrap(x_cont):
                if self.evals >= self.budget: return np.zeros(18)
                return grad_func(np.concatenate([x_cont, x_disc]))[:18]

            x0_18d = np.random.uniform(-1, 1, size=18)

            # MUST PASS jac=grad_wrap TO PREVENT THREAD CRASH
            if grad_func is not None:
                res = minimize(cost_wrap, x0_18d, method='L-BFGS-B', jac=grad_wrap, bounds=[(-1, 1)]*18, options={'maxiter': 50})

            if self.evals >= self.budget: break

        return self.best_f, self.best_x
